"""DOM Reader Eye — structured DOM perception without LLM.

Consumes DistilledDom from gRPC, classifies elements into interactive,
semantic, and noise categories. Pure Python — no LLM call needed.
"""

from __future__ import annotations

from typing import Any

from ans_nerves.eyes.base import BaseEye, EyeReport


_INTERACTIVE_TAGS = frozenset({
    "a", "button", "input", "select", "textarea", "option",
    "form", "label", "fieldset", "datalist", "output",
})

_SEMANTIC_TAGS = frozenset({
    "h1", "h2", "h3", "h4", "h5", "h6", "p", "article",
    "section", "nav", "header", "footer", "main", "aside",
    "table", "ul", "ol", "li", "dl", "dt", "dd",
    "blockquote", "pre", "code", "figure", "figcaption",
})

_NOISE_CLASS_PATTERNS = frozenset({
    "ad", "ads", "advert", "advertisement", "banner",
    "cookie", "consent", "gdpr", "popup", "modal",
    "newsletter", "subscribe", "social", "share",
    "tracking", "tracker", "analytics",
})


def _is_noise(element: dict[str, Any]) -> bool:
    """Classify an element as noise based on CSS classes, IDs, and ARIA roles."""
    css_class = (element.get("css_class") or "").lower()
    css_id = (element.get("css_id") or "").lower()
    role = (element.get("aria_role") or "").lower()

    combined = f"{css_class} {css_id} {role}"
    for pattern in _NOISE_CLASS_PATTERNS:
        if pattern in combined:
            return True
    return False


def _classify_element(element: dict[str, Any]) -> str:
    """Classify a single element as interactive, semantic, or noise."""
    if _is_noise(element):
        return "noise"

    tag = (element.get("tag") or "").lower()
    if tag in _INTERACTIVE_TAGS:
        return "interactive"
    if tag in _SEMANTIC_TAGS:
        return "semantic"

    # Check ARIA roles for interactive hints
    role = (element.get("aria_role") or "").lower()
    if role in {"button", "link", "textbox", "searchbox", "combobox",
                 "checkbox", "radio", "switch", "menuitem", "option", "tab"}:
        return "interactive"

    return "semantic"


class DomReaderEye(BaseEye):
    """Reads distilled DOM and produces structured element lists.

    No LLM call — pure heuristic classification runs in microseconds.
    """

    name = "dom_reader"

    async def observe(self, session_id: str, page_data: dict[str, Any]) -> EyeReport:
        distilled = page_data.get("distilled_dom")
        if distilled is None:
            return EyeReport(
                eye_name=self.name,
                confidence=0.0,
                content={
                    "elements": [],
                    "interactive": [],
                    "semantic_blocks": [],
                    "distraction_flags": [],
                    "mode": "text_only",
                    "error": "No distilled DOM in page_data",
                },
            )

        # Accept both already-parsed dict and JSON string
        if isinstance(distilled, str):
            import json
            try:
                distilled = json.loads(distilled)
            except json.JSONDecodeError:
                return EyeReport(
                    eye_name=self.name,
                    confidence=0.0,
                    content={"error": "Invalid distilled DOM JSON"},
                )

        elements: list[dict[str, Any]] = distilled.get("elements", [])
        mode = distilled.get("mode", "text_only")

        interactive = []
        semantic_blocks = []
        distraction_flags = []

        for el in elements:
            classification = _classify_element(el)

            if classification == "interactive":
                attrs = el.get("attributes", {}) or {}
                interactive.append({
                    "selector": el.get("selector", ""),
                    "element_type": el.get("tag", "unknown"),
                    "label": el.get("text", "") or el.get("aria_label", "") or "",
                    "input_type": attrs.get("type", "text") if el.get("tag") == "input" else None,
                    "placeholder": attrs.get("placeholder", ""),
                    "name": attrs.get("name", ""),
                    "autocomplete": attrs.get("autocomplete", ""),
                    "aria_label": el.get("aria_label", ""),
                    "value": attrs.get("value", ""),
                    "is_visible": el.get("is_visible", True),
                    "is_enabled": el.get("is_enabled", True),
                    "bounding_box": el.get("bounding_box"),
                    "goal_relevance_score": el.get("goal_relevance_score", 0.0),
                })
            elif classification == "noise":
                distraction_flags.append({
                    "selector": el.get("selector", ""),
                    "kind": "classified_by_css",
                    "confidence": 0.85,
                    "text_snippet": (el.get("text") or "")[:100],
                })
            else:
                semantic_blocks.append({
                    "block_type": el.get("tag", "unknown"),
                    "text_content": el.get("text", "") or "",
                    "goal_relevance_score": el.get("goal_relevance_score", 0.0),
                })

        return EyeReport(
            eye_name=self.name,
            confidence=1.0,
            goal_relevance=self._compute_overall_relevance(interactive, semantic_blocks),
            content={
                "elements": elements,
                "interactive": interactive,
                "semantic_blocks": semantic_blocks,
                "distraction_flags": distraction_flags,
                "mode": mode,
                "url": distilled.get("url", ""),
                "title": distilled.get("title", ""),
            },
        )

    @staticmethod
    def _compute_overall_relevance(
        interactive: list[dict[str, Any]],
        semantic_blocks: list[dict[str, Any]],
    ) -> float:
        scores: list[float] = []
        for el in interactive:
            s = el.get("goal_relevance_score", 0.0)
            if isinstance(s, (int, float)):
                scores.append(float(s))
        for blk in semantic_blocks:
            s = blk.get("goal_relevance_score", 0.0)
            if isinstance(s, (int, float)):
                scores.append(float(s))

        if not scores:
            return 0.0
        return sum(scores) / len(scores)

"""Vision Eye — screenshot-based visual understanding via GPT-4.

Receives screenshots as base64-encoded PNG, calls GPT-4 for visual
analysis. Skipped when budget in CRITICAL/EMERGENCY mode.
"""

from __future__ import annotations

from typing import Any

from ans_nerves.eyes.base import BaseEye, EyeReport
from ans_nerves.llm.client import get_llm_client
from ans_nerves.logging import get_logger
from ans_nerves.llm.prompts import (
    VISION_JSON_SCHEMA,
    VISION_SYSTEM,
    build_vision_user_prompt,
)

logger = get_logger(__name__)

_VISION_DEFAULTS: dict[str, Any] = {
    "page_type": "unknown",
    "visible_elements": [],
    "overlays": [],
    "blocked_regions": [],
    "anomalies": [],
}


class VisionEye(BaseEye):
    """Analyses screenshots using GPT-4 vision capabilities."""

    name = "vision"

    async def observe(self, session_id: str, page_data: dict[str, Any]) -> EyeReport:
        screenshot_b64 = page_data.get("screenshot_base64")
        if not screenshot_b64:
            return EyeReport(
                eye_name=self.name,
                confidence=0.0,
                content={**_VISION_DEFAULTS, "error": "No screenshot in page_data"},
            )

        goal_context = page_data.get("goal_context", "")
        page_url = page_data.get("page_url", "")

        # Screenshot-only: no DOM context. Vision observes visual elements,
        # DOM Reader handles structure. Separation avoids hallucinated selectors.
        user_prompt = build_vision_user_prompt(
            goal_context=goal_context,
            page_url=page_url,
        )

        try:
            response = await get_llm_client().complete_vision(
                system_prompt=VISION_SYSTEM,
                user_prompt=user_prompt,
                screenshot_base64=screenshot_b64,
                json_schema=VISION_JSON_SCHEMA,
            )
        except Exception:
            logger.warning("vision: LLM call failed", exc_info=True)
            return EyeReport(
                eye_name=self.name,
                confidence=0.0,
                content={**_VISION_DEFAULTS, "error": "LLM call failed"},
            )

        if response.parsed is None:
            logger.warning("vision: LLM returned unparseable response")
            return EyeReport(
                eye_name=self.name,
                confidence=0.3,
                content={**_VISION_DEFAULTS, "raw_response": response.content[:500]},
            )

        return EyeReport(
            eye_name=self.name,
            confidence=self._compute_confidence(response.parsed),
            content=response.parsed,
        )

    @staticmethod
    def _compute_confidence(parsed: dict[str, Any]) -> float:
        """Lower confidence if no elements found or page type is unknown."""
        if parsed.get("page_type") == "unknown" and not parsed.get("visible_elements"):
            return 0.5
        if not parsed.get("visible_elements"):
            return 0.7
        return 0.9

"""Cross-Eye Coordinator — LLM-powered synthesis of 5 eye reports.

Takes raw EyeReports from all 5 eyes, resolves contradictions via the
defined hierarchy, and produces a unified RoutedSignal for the Decision layer.
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any

from ans_nerves.eyes.base import EyeReport
from ans_nerves.llm.client import get_llm_client
from ans_nerves.llm.prompts import (
    COORDINATOR_JSON_SCHEMA,
    COORDINATOR_SYSTEM,
    build_coordinator_user_prompt,
)
from ans_nerves.logging import get_logger

logger = get_logger(__name__)

# Contradiction resolution hierarchy (matches Rust signal router)
_HIERARCHY = [
    "dom_reader",       # 1. DOM wins on element existence and interaction state
    "vision",            # 2. Vision wins on visual occlusion
    "page_diff",         # 3. Diff wins on whether the page actually changed
    "goal_verifier",     # 4. Goal Verifier wins on whether the goal advanced
    "error_detector",    # 5. Error Detector wins on whether an error occurred
]

_COORDINATOR_DEFAULTS: dict[str, Any] = {
    "unified_perception": "",
    "confidence": 0.0,
    "contradictions": [],
    "recommended_action_hint": None,
    "alerts": [],
}


@dataclass
class RoutedSignal:
    """Unified perception produced after synthesizing all eye reports."""

    unified_perception: str = ""
    alerts: list[dict] = field(default_factory=list)
    confidence: float = 1.0
    recommended_action_hint: str | None = None
    contradictions: list[dict] = field(default_factory=list)


class CrossEyeCoordinator:
    """Synthesizes all 5 eye reports into unified situational awareness.

    Uses GPT-4 to resolve contradictions and produce a natural-language
    summary. Falls back to deterministic merge when LLM is unavailable.
    """

    async def synthesize(
        self,
        reports: list[EyeReport],
        goal_context: str = "",
    ) -> RoutedSignal:
        """Combine all eye reports, resolve contradictions, produce unified signal."""
        if not reports:
            return RoutedSignal(
                unified_perception="No eye reports available.",
                confidence=0.0,
            )

        # Build a JSON summary of all reports for the LLM
        reports_json = json.dumps([
            {
                "eye_name": r.eye_name,
                "confidence": r.confidence,
                "goal_relevance": r.goal_relevance,
                "content": r.content,
            }
            for r in reports
        ])

        user_prompt = build_coordinator_user_prompt(
            eye_reports_json=reports_json,
            goal_context=goal_context,
        )

        try:
            response = await get_llm_client().complete_structured(
                system_prompt=COORDINATOR_SYSTEM,
                user_prompt=user_prompt,
                json_schema=COORDINATOR_JSON_SCHEMA,
            )
        except Exception:
            logger.warning("coordinator: LLM synthesis failed, using fallback")
            return self._fallback_synthesize(reports)

        if response.parsed is None:
            logger.warning("coordinator: LLM returned unparseable JSON, using fallback")
            return self._fallback_synthesize(reports)

        return RoutedSignal(
            unified_perception=response.parsed.get("unified_perception", ""),
            confidence=response.parsed.get("confidence", 0.5),
            recommended_action_hint=response.parsed.get("recommended_action_hint"),
            contradictions=response.parsed.get("contradictions", []),
            alerts=response.parsed.get("alerts", []),
        )

    def _fallback_synthesize(
        self, reports: list[EyeReport], diff_data: dict | None = None,
    ) -> RoutedSignal:
        """Deterministic synthesis using the contradiction hierarchy.

        No LLM — purely structural merge. Includes raw diff summary from
        the Rust diff engine when available, so PageDiff LLM is unnecessary.
        """
        perception_parts: list[str] = []
        highest_confidence = 0.0
        total_relevance = 0.0

        for r in reports:
            if r.confidence > highest_confidence:
                highest_confidence = r.confidence
            total_relevance += r.goal_relevance

        # Summarise each eye's key findings
        for r in reports:
            content = r.content
            if r.eye_name == "dom_reader":
                interactive = content.get("interactive", [])
                noise = len(content.get("distraction_flags", []))
                # Summarise form fields with labels for the planner
                form_fields = []
                for el in interactive:
                    label = el.get("label", "") or el.get("placeholder", "") or el.get("text", "")
                    tag = el.get("element_type", el.get("tag", ""))
                    itype = el.get("input_type", "")
                    name = el.get("name", "")
                    if tag in ("input", "textarea", "select", "button"):
                        desc = f"tag={tag}"
                        if itype and itype != "text":
                            desc += f" type={itype}"
                        if name:
                            desc += f" name={name}"
                        if label:
                            desc += f" label='{label[:40]}'"
                        form_fields.append(desc)
                form_summary = ""
                if form_fields:
                    form_summary = f" fields=[{', '.join(form_fields[:12])}]"
                perception_parts.append(
                    f"DOM: {len(interactive)} interactive, {noise} noise{form_summary}"
                )
            elif r.eye_name == "vision":
                page_type = content.get("page_type", "unknown")
                overlays = len(content.get("overlays", []))
                anomalies = content.get("anomalies", [])
                perception_parts.append(
                    f"Vision: page_type={page_type}, overlays={overlays}"
                )
                if anomalies:
                    perception_parts.append(f"Anomalies: {', '.join(anomalies)}")
            elif r.eye_name == "page_diff":
                summary = content.get("summary", "no_change")
                perception_parts.append(f"Diff: {summary}")
            elif r.eye_name == "goal_verifier":
                met = content.get("criteria_met", False)
                perception_parts.append(
                    f"Verification: criteria_met={met}"
                )
            elif r.eye_name == "error_detector":
                failure = content.get("failure_type", "none")
                desc = content.get("description", "")
                if failure in ("none", "silent_fail") and not desc:
                    pass
                elif desc:
                    perception_parts.append(f"Error: {failure}: {desc}")
                else:
                    perception_parts.append(f"Error: {failure}")

        # Include structural diff summary from Rust engine (no LLM needed)
        if diff_data:
            added = diff_data.get("added", 0)
            removed = diff_data.get("removed", 0)
            summary = diff_data.get("summary", "")
            if isinstance(added, list):
                added = len(added)
            if isinstance(removed, list):
                removed = len(removed)
            if added or removed or summary:
                perception_parts.append(
                    f"Diff: +{added}/-{removed} elements changed"
                )
                if summary:
                    perception_parts[-1] += f" ({summary})"

        avg_relevance = total_relevance / len(reports) if reports else 0.0

        return RoutedSignal(
            unified_perception=" | ".join(perception_parts),
            confidence=highest_confidence,
            recommended_action_hint=None,
            contradictions=[],
            alerts=[],
        )

"""Prompt templates for each Eye and the Goal Decomposer.

Every Eye gets a dedicated system prompt and a helper to build the
user prompt from page state / goal context. Templates stay here so
they can be iterated independently of the eye implementations.
"""

from __future__ import annotations

import json
from typing import Any

# ─────────────────────────────────────────────────────────────
# Vision Eye — screenshot + DOM → structured visual report
# ─────────────────────────────────────────────────────────────

VISION_SYSTEM = """You are the Vision Eye of an autonomous browser agent. Your job is to analyse a screenshot and distilled DOM of a web page and produce a structured report of what is visible.

You are NOT the agent making decisions. You are a sensory organ — observe and report facts, nothing more.

Rules:
1. List only elements that are ACTUALLY visible in the screenshot — not just present in the DOM.
2. Flag any overlays, popups, cookie banners, or modals blocking the main content.
3. Identify the page type (search_form, search_results, product_page, checkout, login, error, article, dashboard, captcha, paywall, unknown).
4. Note any anomalies: broken layouts, missing images, error messages, unexpected redirects.
5. Provide bounding box estimates for key interactive elements."""

VISION_JSON_SCHEMA = {
    "type": "object",
    "properties": {
        "page_type": {
            "type": "string",
            "enum": [
                "search_form", "search_results", "product_page", "checkout",
                "login", "error", "article", "dashboard", "captcha",
                "paywall", "form", "unknown",
            ],
            "description": "The type of page shown.",
        },
        "visible_elements": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "selector": {"type": "string"},
                    "element_type": {"type": "string"},
                    "label": {"type": "string"},
                    "is_visible": {"type": "boolean"},
                    "is_enabled": {"type": "boolean"},
                    "is_blocked": {"type": "boolean"},
                    "bounding_box": {
                        "type": "object",
                        "properties": {
                            "x": {"type": "number"},
                            "y": {"type": "number"},
                            "width": {"type": "number"},
                            "height": {"type": "number"},
                        },
                    },
                },
                "required": ["selector", "element_type", "label", "is_visible"],
            },
            "description": "Key interactive and semantic elements visible on screen.",
        },
        "overlays": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "type": {"type": "string"},
                    "description": {"type": "string"},
                    "blocks_content": {"type": "boolean"},
                },
            },
            "description": "Popups, modals, cookie banners, or other overlays.",
        },
        "blocked_regions": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "description": {"type": "string"},
                    "bounding_box": {
                        "type": "object",
                        "properties": {
                            "x": {"type": "number"},
                            "y": {"type": "number"},
                            "width": {"type": "number"},
                            "height": {"type": "number"},
                        },
                    },
                },
            },
            "description": "Regions of the page occluded by overlays or rendering issues.",
        },
        "anomalies": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Broken layouts, error messages, missing content, unexpected states.",
        },
    },
    "required": ["page_type", "visible_elements", "overlays", "anomalies"],
}


def build_vision_user_prompt(
    goal_context: str = "",
    page_url: str = "",
) -> str:
    """Build a screenshot-only Vision prompt — no DOM context.

    Vision's job is to observe what's in the screenshot, not to correlate
    DOM elements. DOM Reader handles structure. Separating concerns avoids
    hallucinated selectors and saves ~3000 input tokens per call.
    """
    parts = []
    if goal_context:
        parts.append(f"<goal>\n{goal_context}\n</goal>")
    if page_url:
        parts.append(f"<page_url>\n{page_url}\n</page_url>")
    parts.append(
        "Analyse the screenshot of this page (attached as an image). "
        "Report what is visible, what is blocked, what type of page this is, "
        "and any anomalies present."
    )
    return "\n\n".join(parts)


# ─────────────────────────────────────────────────────────────
# Goal Verifier Eye — page state + criteria → verification
# ─────────────────────────────────────────────────────────────

VERIFIER_SYSTEM = """You are the Goal Verifier Eye of an autonomous browser agent. Your job is to check whether a specific sub-goal or criterion has been met, given the current page state.

You are NOT the agent. Your only job is to verify, factually and conservatively.

Rules:
1. Only mark a criterion as met if there is CLEAR evidence in the provided page state.
2. If you are unsure, set confidence low and criteria_met to false.
3. Use the page URL, visible text, and DOM element states as evidence.
4. If the evidence is ambiguous, explain why in the reasoning field."""

VERIFIER_JSON_SCHEMA = {
    "type": "object",
    "properties": {
        "criteria_met": {
            "type": "boolean",
            "description": "Whether ALL criteria for this sub-goal are satisfied.",
        },
        "confidence": {
            "type": "number",
            "description": "Confidence 0.0-1.0 in this verdict.",
        },
        "criteria_status": {
            "type": "object",
            "description": "Per-criterion status with evidence.",
            "additionalProperties": {
                "type": "object",
                "properties": {
                    "met": {"type": "boolean"},
                    "evidence": {"type": "string"},
                },
            },
        },
        "sub_goal_advanced": {
            "type": "boolean",
            "description": "True if any progress was made toward the sub-goal, even if not complete.",
        },
        "reasoning": {
            "type": "string",
            "description": "Step-by-step reasoning. What was checked and what was found.",
        },
        "blocking_issues": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Anything preventing the sub-goal from completing.",
        },
    },
    "required": ["criteria_met", "confidence", "reasoning"],
}


def build_verifier_user_prompt(
    sub_goal_description: str,
    success_criteria: list[str],
    page_url: str,
    page_title: str,
    visible_text: list[str],
    dom_summary: str = "",
    diff_summary: str = "",
) -> str:
    criteria_block = "\n".join(f"  {i+1}. {c}" for i, c in enumerate(success_criteria))
    text_block = "\n".join(visible_text[:100])  # cap at 100 lines

    parts = [
        f"<sub_goal>\n{sub_goal_description}\n</sub_goal>",
        f"<success_criteria>\n{criteria_block}\n</success_criteria>",
        f"<page>\nURL: {page_url}\nTitle: {page_title}\n</page>",
        f"<visible_text>\n{text_block}\n</visible_text>",
    ]
    if dom_summary:
        parts.append(f"<dom_summary>\n{dom_summary}\n</dom_summary>")
    if diff_summary:
        parts.append(f"<diff_summary>\n{diff_summary}\n</diff_summary>")

    # Truncate DOM summary to reduce input tokens
    if dom_summary:
        dom_summary = dom_summary[:2000]
    parts.append(
        "Verify whether the success criteria are met given the current page state. "
        "Be conservative — only mark criteria as met with clear evidence."
    )
    return "\n\n".join(parts)


# ─────────────────────────────────────────────────────────────
# Error Detector Eye — page state → failure classification
# ─────────────────────────────────────────────────────────────

ERROR_DETECTOR_SYSTEM = """You are the Error Detector Eye of an autonomous browser agent. Your job is to classify what went wrong when an action fails or the page state is unexpected.

You are NOT the agent. Classify the failure and suggest recovery actions.

Failure types:
- silent_fail: Action executed but had no visible effect. Page unchanged.
- wrong_element: Clicked/typed the wrong element. Expected element not found.
- blocked_interaction: Element exists but is blocked by an overlay, disabled, or hidden.
- state_mismatch: Page state doesn't match what was expected. Wrong page loaded.
- goal_drift: Action succeeded technically but didn't advance the goal.
- timeout: Page took too long to load or element didn't become interactive.
- navigation_error: Navigation failed — wrong URL, 404, 500, DNS error.
- captcha: A CAPTCHA or bot-detection challenge is blocking progress.
- paywall: Content is behind a paywall.
- login_wall: Login required to proceed."""

ERROR_JSON_SCHEMA = {
    "type": "object",
    "properties": {
        "failure_type": {
            "type": "string",
            "enum": [
                "silent_fail", "wrong_element", "blocked_interaction",
                "state_mismatch", "goal_drift", "timeout",
                "navigation_error", "captcha", "paywall", "login_wall",
            ],
        },
        "description": {
            "type": "string",
            "description": "What went wrong in one sentence.",
        },
        "should_retry": {
            "type": "boolean",
            "description": "Whether retrying the same action could help.",
        },
        "max_retries": {
            "type": "integer",
            "description": "Suggested max retry count (1-3).",
        },
        "recovery_actions": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Ordered recovery steps to try.",
        },
        "escalation_needed": {
            "type": "boolean",
            "description": "True if human intervention or goal re-planning is needed.",
        },
    },
    "required": ["failure_type", "description", "should_retry", "recovery_actions"],
}


def build_error_detector_user_prompt(
    action_description: str,
    error_message: str,
    page_url: str,
    page_title: str,
    visible_text: list[str],
    goal_context: str = "",
) -> str:
    text_block = "\n".join(visible_text[:50])
    parts = [
        f"<failed_action>\n{action_description}\n</failed_action>",
        f"<error>\n{error_message}\n</error>",
